# -*- coding: utf-8 -*-
import os
import sys

from ._version import __version__  # noqa: F403,F401

if os.name == "nt":  # pragma: no cover
    os.environ["PATH"] = (
        f"{os.path.abspath(os.path.dirname(__file__))}"
        f"{os.pathsep}"
        f"{os.environ['PATH']}"
    )

_pango_available = False
try:
    from .register_font import *  # isort:skip # noqa: F403,F401
    from .cmanimpango import *  # noqa: F403,F401
    from .enums import *  # noqa: F403,F401
    _pango_available = True
except (ImportError, OSError):
    # iOS: .so frameworks may not load on first run or may need re-deploy.
    # Provide stub fallbacks so manim can still work with Cairo renderer.
    import warnings
    warnings.warn("ManimPango native libs unavailable; using stub fallbacks for Cairo rendering.", stacklevel=2)

    # Stub enums
    class PangoUtils:
        @staticmethod
        def str2style(s): return 0
        @staticmethod
        def str2weight(s): return 400
        @staticmethod
        def remove_last_M(s): return s

    class Style:
        NORMAL = 0
        ITALIC = 1
        OBLIQUE = 2

    class Weight:
        NORMAL = 400
        BOLD = 700
        THIN = 100
        LIGHT = 300
        BOOK = 380
        MEDIUM = 500
        SEMIBOLD = 600
        ULTRABOLD = 800
        HEAVY = 900
        ULTRAHEAVY = 1000

    # Stub text layout using CoreText via basic measurement
    class TextSetting:
        def __init__(self, start=0, end=0, font='', slant='NORMAL', weight='NORMAL',
                     line_num=-1, color=None, is_new_line=False, **kwargs):
            self.start = start
            self.end = end
            self.font = font
            self.slant = slant
            self.weight = weight
            self.line_num = line_num
            self.color = color
            self.is_new_line = is_new_line

    def text2svg(settings, size, line_spacing, disable_liga, file_name,
                 START_X=0, START_Y=0, width=600, height=400, orig_text='',
                 pango_width=None):
        """iOS stub: returns empty SVG (no font rendering without Pango).
        Text() mobjects will be invisible but won't cause artifacts."""
        import os
        # Empty SVG with just a tiny transparent rect so manim doesn't error
        svg = '<svg xmlns="http://www.w3.org/2000/svg" width="1" height="1"></svg>'
        if file_name:
            os.makedirs(os.path.dirname(str(file_name)) or '.', exist_ok=True)
            with open(str(file_name), 'w') as fobj:
                fobj.write(svg)
            return str(file_name)
        return svg

    def markup2svg(text, font='', slant='NORMAL', weight='NORMAL', size=1,
                   _placeholder=None, disable_ligatures=False, file_name='',
                   START_X=0, START_Y=0, width=600, height=400, **kwargs):
        """Render markup text to SVG using <rect> elements (same as text2svg)."""
        import re, os
        plain = re.sub(r'<[^>]+>', '', str(text))
        # Reuse text2svg logic with a fake settings list
        settings = [TextSetting(start=0, end=len(plain), font=font or '', color='white')]
        return text2svg(settings, size, 0, disable_ligatures, file_name,
                       START_X, START_Y, width, height, plain)

    def list_fonts():
        """Return empty font list (no fontconfig on iOS)."""
        return []

    def register_font(font_path):
        return True

    def unregister_font(font_path):
        return True

    registered_fonts = set()

    class RegisteredFont:
        def __init__(self, path=''):
            self.path = path

    class Variant:
        NORMAL = 0
        SMALL_CAPS = 1

    class Alignment:
        LEFT = 0
        CENTER = 1
        RIGHT = 2

    class MarkupUtils:
        @staticmethod
        def validate(markup):
            """Stub: validate Pango markup. Returns empty string (valid) on iOS."""
            return ""

        @staticmethod
        def text2svg(text, font=None, slant='NORMAL', weight='NORMAL', size=1,
                     _placeholder=None, disable_liga=False, file_name='',
                     START_X=0, START_Y=0, width=600, height=400, *,
                     justify=None, indent=None, line_spacing=None,
                     alignment=None, pango_width=None):
            """Render markup to SVG using <rect> elements (same approach as text2svg)."""
            import re
            plain = re.sub(r'<[^>]+>', '', str(text))
            settings = [TextSetting(start=0, end=len(plain), font=font or '', color='white')]
            return text2svg(settings, size, 0, disable_liga, file_name,
                           START_X, START_Y, width, height, plain)

    def pango_version():
        """Stub: return placeholder Pango version on iOS."""
        return "1.50.0"

    def cairo_version():
        """Stub: return placeholder Cairo version on iOS."""
        return "1.16.0"

    __all__ = [
        'PangoUtils', 'Style', 'Weight', 'Variant', 'Alignment',
        'TextSetting', 'MarkupUtils',
        'text2svg', 'markup2svg', 'list_fonts',
        'register_font', 'unregister_font', 'registered_fonts', 'RegisteredFont',
        'pango_version', 'cairo_version',
    ]
